SELECT AnalisiCancellazioniSKU_step0_dativendite.*, Item.Description, Item.[Description 2], Item.[Line Code], [Variable Code].Description AS Color, Item.[Season Typology], Item.[Product Family], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], [MustBuy-ArticoloColore].[Must Buy], Item.[Country_Region of Origin Code]
FROM (AnalisiCancellazioniSKU_step0_dativendite INNER JOIN ((Item INNER JOIN [Variable Code] ON Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON (AnalisiCancellazioniSKU_step0_dativendite.No_ = Item.No_) AND (AnalisiCancellazioniSKU_step0_dativendite.ColorCode = [Variable Code].[Variable Code])) LEFT JOIN [MustBuy-ArticoloColore] ON (AnalisiCancellazioniSKU_step0_dativendite.ColorCode = [MustBuy-ArticoloColore].[Variable Code 01]) AND (AnalisiCancellazioniSKU_step0_dativendite.No_ = [MustBuy-ArticoloColore].[Model Item No_])
WHERE ([Season Code]='E24');

